"""
MKT Christ Commentary — 1 Kings chapters 6–7
Run: python3 scripts/zc-christ-1kings-6-7.py

Source data used:
- data/interlinear/1kings.json
- data/translation/draft/mediating/1kings.json
- data/commentary/mkt-christ/1kings.json (existing: chs 1–2, 19 already written)

Key decisions in this range:
- Temple construction chapters: classified primarily as shadow/type for the dwelling-of-God trajectory
  (Tabernacle → Solomonic temple → body of Christ → new creation temple; John 1:14; 2:19-21; Rev 21)
- 6:7 (silence of construction): shadow of the spiritual temple built without force (1 Pet 2:5)
- 6:11-13 (conditional covenant): direct tie to John 2:19-21 (temple = Christ's body, unconditional)
- 6:19-21 (inner sanctuary for the ark): shadow of Christ's entry into the heavenly sanctuary (Heb 9:24)
- 6:23-28 (cherubim): shadow of John 20:12 (angels at the tomb echoing the mercy-seat layout)
- 6:29-35 (Eden imagery: cherubim, palm trees, flowers): shadow of Rev 22 (paradise restored)
- Holy of holies as cube (20x20x20): shadow of Rev 21:16 (New Jerusalem as cube = unmediated presence)
- 7:15-22 (Jachin and Boaz): theme — divine establishment and strength; Rev 3:12 (victorious pillar)
- 7:23-26 (molten sea): shadow of Rev 4:6 (glassy sea before the throne = chaos stilled)
- 7:13-14 (Hiram the Gentile craftsman): theme of Gentile inclusion in the house of God
- 7:48-50 (gold furnishings): bread of Presence → John 6:35; lampstands → John 8:12; Rev 1:12-13
- 7:51 (completion formula): shadow of John 19:30 ("It is finished")
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

KINGS1 = {
  "6": {
    "1": "<p>A shadow: the 480th year after the Exodus positions the temple at the center of Israel's redemptive timeline — 12 × 40, twelve tribes and the wilderness-generation number. Every 40-year unit is stamped with the same meaning: God's people in testing, sustained toward a destination. John 2:20 resets the calculation: the temple took 46 years to renovate, yet Jesus speaks of raising &lsquo;this temple&rsquo; in three days. The three-day resurrection becomes the new temporal landmark against which all temple-theology is calibrated.</p>",
    "2": "<p>A shadow: the main hall (60 × 20 × 30 cubits) is the outer shell of the sanctuary, but the holy of holies cut from its rear is a perfect cube — 20 × 20 × 20 cubits (v16). The cube is the geometry of unmediated divine presence: nothing asymmetrical, all dimensions equal. Rev 21:16 reuses this geometry for the New Jerusalem — &lsquo;its length and width and height are equal&rsquo; — extending what the holy of holies was in miniature to an entire city. The temple says: God dwells with his people here, in this space. The New Jerusalem says: God dwells with his people everywhere.</p>",
    "3": "<p>The theme of God's revelation of himself: the portico, running the full width of the house, is the first element of graduated approach to God — outer court, portico, main hall, inner sanctuary. Each threshold represents a degree of holiness and access. The NT abolishes this architecture of graduated access: the veil separating the inner sanctuary tears at the crucifixion (Matt 27:51), and Heb 10:19-20 draws the consequence — &lsquo;we have confidence to enter the holy places by the blood of Jesus, by the new and living way that he opened for us through the curtain.&rsquo;</p>",
    "4": "<p>The recessed window frames let light in while controlling its source, so the sanctuary interior was lit without the windows being intrusive. The theme: YHWH dwells in light unapproachable (1 Tim 6:16), yet accommodates his presence to human dwelling. The temple is the architectural expression of divine condescension — YHWH fitting his dwelling to human capacity. The incarnation is the full accommodation: the Word in flesh, the unapproachable light made touchable.</p>",
    "5": "<p>The three-story annexe around the temple walls provides chambers for storage and priestly use without compromising the main structure's integrity. The theme of God's provision: the house of YHWH is surrounded by service structures that sustain its ongoing worship. This theme of infrastructure supporting the central sanctuary recurs in the NT's teaching on spiritual gifts — varied ministries (1 Cor 12:28; Eph 4:11-12) surrounding and supporting the body of Christ.</p>",
    "6": "<p>The annexe floors are progressively wider (five, six, seven cubits) so the temple walls are not weakened by inserted beams. The builder's care for structural integrity: the outer serving the inner without undermining it. A shadow: the structures surrounding Christ's church (ministry, service, institution) must not compromise his central lordship. The temple's architectural principle is ecclesiological: support structures serve by connecting, not by penetrating the sacred center.</p>",
    "7": "<p>A shadow: &lsquo;No hammer, chisel, or iron tool was heard at the building site while it was being built.&rsquo; The stones were dressed at the quarry and fitted in silence. 1 Pet 2:5 describes believers as &lsquo;living stones being built up as a spiritual house&rsquo; — the shaping happens in individual life (the quarry) before assembly into the community. The building of the spiritual temple occurs without the violence and noise of human coercion; God&rsquo;s construction of his people is quiet, personal, preparatory, then joined in silence at the site of assembly.</p>",
    "8": "<p>The entrance to the annexe on the south side, with stairs connecting the floors, is a detail of ordered access. The theme of ordered approach to God's dwelling runs through the temple's design and is fulfilled in Christ's declaration: &lsquo;I am the way&rsquo; (John 14:6). The one entrance, the single stairway, the structured approach — all figure the one mediator (1 Tim 2:5) through whom the ascent to God is made.</p>",
    "9": "<p>The house &lsquo;built to completion&rsquo; and covered with cedar. Every completion notice in the OT narrative anticipates the ultimate completion: the tabernacle (Exod 40:33), the temple (1 Kgs 7:51), the second temple (Ezra 6:15), Christ&rsquo;s work (John 19:30). The cedar covering, fragrant and incorruptible by ordinary decay, is the material of permanence: the dwelling of God is built to last. Yet every physical temple was temporary — Solomon&rsquo;s was destroyed, the second was destroyed. The permanent temple is the one built in three days (John 2:19-21): the risen body of Christ and the community built into him.</p>",
    "10": "<p>The annexe attached to the house with cedar beams — each story five cubits. The unity of the structure: the surrounding service spaces are joined to the central sanctuary by the same material, the same height, continuous with the whole. The theme of unity in the body of Christ: Eph 2:21, &lsquo;in whom the whole structure, being joined together, grows into a holy temple in the Lord.&rsquo; The joints and beams are the ministries and relationships that connect the diverse members to the one dwelling of God.</p>",
    "11": "<p>YHWH speaks directly to Solomon during the construction: &lsquo;concerning this house you are building.&rsquo; The divine word accompanies the physical construction — the temple is not a human achievement alone but a divinely-narrated act. The NT parallel: Jesus &lsquo;I will build my church&rsquo; (Matt 16:18) is the divine word accompanying and authorizing the construction of the new temple. The builder is Christ, not Peter; the church is built by divine speech and act.</p>",
    "12": "<p>The conditional covenant: &lsquo;if you walk in my statutes, obey my ordinances, and keep all my commandments.&rsquo; The temple&rsquo;s permanence is conditional on Solomon&rsquo;s obedience — a condition Solomon ultimately fails (1 Kgs 11). The conditional covenant reveals the structural problem: no human king can sustain the conditions of the covenant from the inside. The NT fulfillment is the replacement of the conditional with the unconditional: Heb 8:6-7, &lsquo;a better covenant, enacted on better promises.&rsquo; Jesus is the one who walked in all the statutes, obeyed all the ordinances, kept all the commandments — on behalf of the people, in their place, so that the new temple-promise is secured by his performance, not theirs.</p>",
    "13": "<p>A direct fulfillment trajectory: &lsquo;I will dwell among the Israelites and will not abandon my people Israel.&rsquo; This unconditional half of the promise (in tension with v12&rsquo;s conditional) is the ground of YHWH&rsquo;s faithfulness even through disobedience and exile. John 1:14 fulfills it: <em>eskēnōsen en hēmin</em>, &lsquo;he tabernacled among us&rsquo; — the divine dwelling permanently realized in the incarnation. &lsquo;I will not abandon my people&rsquo; reaches its certain basis in Rom 8:38-39: nothing in creation can separate us from the love of God in Christ Jesus. The temple promise stands because God keeps it in Christ.</p>",
    "14": "<p>A shadow: &lsquo;So Solomon built the house and finished it.&rsquo; Each completion of a sacred structure in Israel&rsquo;s narrative stands in a sequence: Moses finishes the tabernacle (Exod 40:33); Solomon finishes the temple; Jesus says &lsquo;It is finished&rsquo; (John 19:30). The accumulation of these completions reveals the pattern: YHWH&rsquo;s dwelling with his people is repeatedly established, repeatedly disrupted, and awaiting a completion that will not be followed by destruction. The resurrection establishes that completion; Rev 21:3 is its eternal articulation: &lsquo;the dwelling place of God is with man.&rsquo;</p>",
    "15": "<p>The cedar lining covers every surface from floor to ceiling — &lsquo;he covered the inside with wood; no stone was visible.&rsquo; The entire natural material of the structure (hewn stone) is hidden under the crafted beauty of cedar. A shadow: in Christ the harsh material of human nature — broken, fractured, under judgment — is clothed with his righteousness. 2 Cor 5:21: &lsquo;so that in him we might become the righteousness of God.&rsquo; What is visible in the holy is not the raw material but the transformed, beautiful surface.</p>",
    "16": "<p>The inner sanctuary — the holy of holies — is partitioned off from the main hall: twenty cubits set apart, floor to ceiling in cedar. This is the most restricted space in Israel, entered once a year by the high priest on the Day of Atonement (Lev 16). A shadow and direct fulfillment: Heb 9:3, 7-8 interprets this curtain as indicating that &lsquo;the way into the holy places is not yet opened.&rsquo; The way in was always provisional, always restricted, always blood-mediated — until Heb 10:19-22 announces the new and living way through the curtain of Christ&rsquo;s flesh.</p>",
    "17": "<p>The main hall is forty cubits long — the wilderness number applied to the space of worship. The theme: the entire place of approach to God is stamped with the number of testing and pilgrimage. The NT people of God are still in the forty, still in the main hall on the way to the holy of holies of the final glory. Yet Heb 4:9-11 says a Sabbath rest remains; the 40-day/year wilderness is the current age; the holy of holies rest awaits.</p>",
    "18": "<p>Cedar carved with gourds and open flowers — vegetative motifs filling the space within the sanctuary. The temple interior reproduces paradise: vegetative abundance, fruit and flower, under the roof of YHWH&rsquo;s dwelling. Gen 2 (the garden where God walked) and Rev 22:1-2 (the garden at the center of the new creation) frame this imagery. The temple is the preserved remnant of Eden, the forward vision of the restored garden — God&rsquo;s house is always a garden, and the garden is always God&rsquo;s house.</p>",
    "19": "<p>A shadow: the inner sanctuary prepared &lsquo;to receive the ark of the covenant of the LORD.&rsquo; The ark is YHWH&rsquo;s footstool-throne, the locus of his covenant presence, the object of the whole temple&rsquo;s existence. Heb 9:24: Christ entered &lsquo;into heaven itself, now to appear in the presence of God on our behalf.&rsquo; The ark in the holy of holies is the OT form of Christ&rsquo;s heavenly intercession: the representative who stands in the presence, making atonement and bearing the covenant.</p>",
    "20": "<p>A shadow: the holy of holies is twenty cubits in every dimension — length, width, and height equal. The perfect cube. Rev 21:16 applies the same geometry to the New Jerusalem, whose &lsquo;length and width and height are equal.&rsquo; The cube-geometry means: in the holy of holies, you are completely surrounded by the divine presence, no direction more holy than another. In the new creation, the same — YHWH&rsquo;s glory fills all dimensions, there is no periphery, no profane space remaining. The holy of holies is the architectural promise of what the new creation will be.</p>",
    "21": "<p>Solomon overlaid the inside of the house with pure gold — the fullest possible expression of the divine dwelling&rsquo;s value. The gold interior is not decoration; it is the material statement that nothing of lesser worth can adequately represent the presence of YHWH. Gold chains across the entrance to the inner sanctuary: the barrier is present but penetrable, decorated with the material of divine majesty. The theme of costly access: the NT announces that access to God comes at an even greater cost than the gold — through the &lsquo;precious blood of Christ, like that of a lamb without blemish&rsquo; (1 Pet 1:19).</p>",
    "22": "<p>The entire house overlaid with gold &lsquo;until it was entirely finished&rsquo;; the altar before the inner sanctuary likewise overlaid. The altar of incense before the veil corresponds to the intercession of prayer rising to God. Rev 8:3-4: an angel stands at the golden altar before the throne with golden incense and the prayers of all the saints rise before God. The Solomonic altar before the inner sanctuary foreshadows the heavenly altar of intercession — the prayers of God&rsquo;s people ascending perpetually in the heavenly sanctuary where Christ intercedes.</p>",
    "23": "<p>Two cherubim of olivewood, each ten cubits tall, are placed in the inner sanctuary — the guardians of YHWH&rsquo;s throne who flank the ark of the covenant. The cherubim first appear in Gen 3:24 as guardians of Eden; they are on the mercy seat (Exod 25:18-22); they dominate Ezekiel&rsquo;s throne-vision (Ezek 1; 10). Solomon&rsquo;s monumental cherubim in olivewood (incorruptible material) are the permanent articulation of the throne&rsquo;s guardianship. Their presence in the holy of holies declares: this is the throne-room of YHWH, and it is guarded. John 20:12 places two angels in white &lsquo;one at the head and one at the feet where Jesus&rsquo;s body had lain&rsquo; — the empty tomb mirrors the mercy seat, two guardian-figures at either end of the place where atonement was accomplished.</p>",
    "24": "<p>One wing five cubits, the other five cubits — ten cubits wingtip to wingtip. The outstretched wings of the cherubim represent the protective covering of YHWH&rsquo;s divine care. Ps 91:4: &lsquo;he will cover you with his pinions, and under his wings you will find refuge.&rsquo; The architectural covering of the holy of holies by the cherubim wings images the same protective presence. Matt 23:37: &lsquo;how often would I have gathered your children together as a hen gathers her brood under her wings.&rsquo; Jesus speaks as YHWH — the one whose wings spread over the holy of holies now speaks of gathering Jerusalem.</p>",
    "25": "<p>&lsquo;Both cherubim were the same size and shape&rsquo; — identical guardians, equal in dimension. The theme of divine symmetry: the throne of YHWH is not asymmetric, not tilted toward one side of the covenant. The two cherubim frame the mercy seat equally; justice and mercy are equally held in the one presence. Rom 3:26: God is &lsquo;just and the justifier of the one who has faith in Jesus&rsquo; — the symmetry of justice and mercy resolved at the cross, not dissolved.</p>",
    "26": "<p>Each cherub ten cubits tall — together, the cherubim span the entire width of the inner sanctuary (v27). These are not decorative features but architecturally dominant presences: the holy of holies is a cherub-filled room, the throne of YHWH defined by its heavenly guardians. Revelation&rsquo;s heavenly throne room (Rev 4-5) is similarly dominated by the four living creatures (drawn from Ezekiel&rsquo;s cherubim vision) who fill the space before the throne with ceaseless worship. The temple is a model of heaven.</p>",
    "27": "<p>A shadow: &lsquo;The cherubim&rsquo;s wings were spread out so that one wing of the first touched one wall and one wing of the second touched the other wall, while their other wings met in the center.&rsquo; The cherubim span wall to wall, their inner wings touching at the center over the ark — forming a canopy over the mercy seat. The divine presence is not hovering at one side but centrally spanning all. The NT parallel is the Spirit&rsquo;s presence among the gathered community (Matt 18:20: &lsquo;where two or three are gathered in my name, there am I among them&rsquo;) — Christ at the center, spanning the community.</p>",
    "28": "&lsquo;He overlaid the cherubim with gold.&rsquo; The cherubim, already made of olivewood (incorruptible), are additionally covered in gold (transcendent value). The dual character: incorruptibility and glory together. The resurrection body is both incorruptible (1 Cor 15:42: &lsquo;raised imperishable&rsquo;) and glorious (1 Cor 15:43: &lsquo;raised in glory&rsquo;) — the two qualities the cherubim embody in their material composition.",
    "29": "<p>A shadow: &lsquo;On all the walls throughout the house... he carved figures of cherubim, palm trees, and open flowers.&rsquo; The entire temple interior is covered with the garden-of-paradise motifs: cherubim (divine presence and protection), palm trees (life and righteousness, cf. Ps 92:12), open flowers (created beauty in full bloom). Solomon&rsquo;s temple recreates Eden in carved form. Rev 22:2 fulfills this: the tree of life bearing twelve fruits, its leaves for healing of the nations — Eden restored not in stone but in the redeemed creation. The carved paradise anticipates the real paradise.</p>",
    "30": "&lsquo;He overlaid the floor of the house with gold, in both the inner and outer rooms.&rsquo; The floor under every footstep is gold — not marble, not decorated stone, but pure gold. In the holy dwelling, even the ground you walk on reflects the divine glory. Rev 21:21: &lsquo;the street of the city was pure gold, like transparent glass.&rsquo; The New Jerusalem extends what the holy of holies floor embodied: walking in the presence of God is walking on gold.",
    "31": "<p>The olivewood doors for the inner sanctuary entrance with five-sided doorposts. Olivewood is incorruptible, resistant to decay — the material of permanence chosen for the threshold of the most sacred space. The five-sided (pentagonal) doorposts are unusual, departing from the standard rectangular frame. The oddity may mark the threshold as uniquely liminal: entering here is entering a space that operates by different rules. John 10:9: &lsquo;I am the door&rsquo; — entrance into the divine presence is through a person, not a space.</p>",
    "32": "<p>The olivewood doors carved with cherubim, palm trees, and open flowers, overlaid with gold. The doors that open into the most sacred space are themselves covered with the paradise motifs and the gold of divine value. Every element of the entrance communicates what the space within is: garden-like, guarded, golden. The NT fulfillment: Jesus as the door (John 10:9), the way (John 14:6), the entrance — is himself covered with the &lsquo;gold&rsquo; of divine glory (John 1:14: &lsquo;we have seen his glory&rsquo;) and flanked by the angels of his resurrection presence.</p>",
    "33": "<p>Square doorposts for the entrance to the main hall — the fourfold symmetry of the outer entrance. The square at the entrance to the main hall, the five-sided at the inner sanctuary, the cube of the holy of holies: the geometry changes as you move inward, becoming more unusual, more set apart. The spatial escalation of sacred geometry communicates that holiness is not uniform — the inner presence intensifies. But the NT erases this gradient: all believers are &lsquo;a royal priesthood, a holy nation&rsquo; (1 Pet 2:9), all admitted into the full presence.</p>",
    "34": "<p>Cypress wood doors with two folding leaves each — the practicality of large folding doors for the main entrance. The accessibility implied by functional doors: the main hall is entered by many; the inner sanctuary by one. The gradation of access in the temple architecture is the architectural argument for the uniqueness of Christ as high priest. He enters the inner sanctuary; we enter through him. Heb 4:14: &lsquo;since then we have a great high priest who has passed through the heavens, Jesus, the Son of God.&rsquo;</p>",
    "35": "<p>The carved cherubim, palm trees, and flowers on the cypress doors overlaid with evenly applied gold — consistency of material and motif from outer to inner. The paradise theme is not reserved for the holiest spaces alone; it decorates the doors the common priest uses. The theme of divine beauty extending outward: God&rsquo;s glory is not compressed into the holy of holies alone but radiates outward through every element of the house. Eph 3:10: the &lsquo;manifold wisdom of God&rsquo; is made known through the church — the glory is meant to radiate outward.</p>",
    "36": "<p>The inner court built with alternating stone and cedar courses — three stone, one cedar. The building material of the courts differs from the sanctuary itself: less pure gold, more stone and timber. The gradation from the worshipping community (courts) to the divine presence (the house) is architectural theology: God meets his people in the courts, and the distance between the courts and the holy of holies is the distance Christ has bridged. Eph 2:13: &lsquo;you who once were far off have been brought near by the blood of Christ.&rsquo;</p>",
    "37": "<p>The foundation laid in the fourth year, in the month of Ziv. The foundation is the point from which the entire structure is measured. A direct connection: 1 Cor 3:11, &lsquo;no one can lay a foundation other than that which is laid, which is Jesus Christ.&rsquo; Solomon&rsquo;s temple has a fixed temporal foundation; the church of Christ has a fixed christological foundation. The month Ziv (the second month) is identified in the LXX with the spring flourishing season — the foundation of the eternal dwelling laid at the time of new growth.</p>",
    "38": "<p>The temple completed in the eleventh year, in the month of Bul — the eighth month. Seven years of construction (from the fourth year to the eleventh year). The seven-year building period carries the sabbath number: the dwelling of God is built in the fullness-number of time. Yet the completion in the eighth month points beyond the seven: after the sabbath comes the eighth day, the day of resurrection and new beginning. The Christian eighth-day theology (Sunday as the day after the sabbath, the day of resurrection) finds its OT shadow in the temple completed in the eighth month after a seven-year labor.</p>"
  },
  "7": {
    "1": "<p>Solomon took thirteen years to build his own palace — compared to seven for the temple (6:38). The disproportion is theologically noted: the king&rsquo;s house exceeds the house of God in construction time. Haggai 1:4 later condemns this pattern in the post-exilic community: &lsquo;Is it a time for you yourselves to dwell in your paneled houses, while this house lies in ruins?&rsquo; The seeds of Solomon&rsquo;s eventual failure (ch 11) are visible in this early asymmetry of devotion. The theme of God&rsquo;s kingdom being first is the Solomonic lesson taken up in Matt 6:33: &lsquo;seek first the kingdom of God and his righteousness.&rsquo;</p>",
    "2": "<p>The House of the Forest of Lebanon — named for its cedar columns simulating a forest canopy — is the largest of the palace complex buildings. The king&rsquo;s own house outscales every domestic structure in Israel. The theme of royal glory: Solomon&rsquo;s palace complex demonstrates the reign of the Davidic king at its material apex. Yet Matt 6:29 uses Solomon&rsquo;s glory as the foil: &lsquo;even Solomon in all his glory was not arrayed like one of these&rsquo; (the lilies of the field). The glory of God&rsquo;s creation surpasses royal achievement; Solomon&rsquo;s palace is the OT&rsquo;s maximum statement of human royal glory, surpassed by the common gift of divine creation.</p>",
    "3": "<p>The cedar ceiling above forty-five pillars — fifteen to each of three rows. The forest-of-Lebanon metaphor is architectural: columns of cedar simulate trees, beams simulate branches, the ceiling simulates a canopy. The idea of the king dwelling in a cultivated version of the natural world. The theme of re-ordered creation: the Davidic king reorganizes the natural to serve the purposes of governance and worship. The messianic king of Isa 11:6-9 is the fulfillment: nature itself re-ordered under his reign, the wolf lying with the lamb, the child with the serpent.</p>",
    "4": "<p>Windows in three rows facing one another. The Hall of Pillars is a space designed for visibility and transparency — three rows of windows so light and sight penetrate from every level. The theme of divine transparency: God&rsquo;s governance is not hidden in darkness. The NT fulfillment is the revelation of the &lsquo;mystery hidden for ages&rsquo; (Eph 3:9-10): what was partial and shadowed in the Solomonic court is now made fully visible in the gospel.</p>",
    "5": "<p>All doorways and doorframes rectangular, windows facing one another in three tiers. The visual symmetry of the palace buildings — consistent, ordered, proportional. The theme of God&rsquo;s creation as ordered and proportioned (Gen 1: God separates, names, and assigns); the palace complex mirrors this order in human construction. The king&rsquo;s dwelling as a microcosm of divine order — fulfilled in the one who is &lsquo;before all things, and in him all things hold together&rsquo; (Col 1:17).</p>",
    "6": "<p>The Hall of Pillars with colonnaded porch — the ceremonial threshold of the palace complex. Columns at the threshold define the space between the public and the royal: you pass through the pillars to approach the throne. A shadow: the temple&rsquo;s own pillars (Jachin and Boaz, vv21-22) stand at the same threshold position. The columns of the heavenly throne room are the enthroned figures who surround the divine presence. The Davidic king&rsquo;s architectural pillars are a human echo of the divine throne&rsquo;s pillared approaches.</p>",
    "7": "<p>The Hall of the Throne and the Hall of Judgment — the same space serves both royal enthronement and judicial verdict. Solomon&rsquo;s throne is simultaneously his judging seat, &lsquo;where he would pronounce verdicts.&rsquo; The Davidic king as judge is a messianic theme: Isa 11:3-5, &lsquo;he shall judge the poor with righteousness&rsquo;; Ps 72:2, &lsquo;may he judge your people with righteousness.&rsquo; Acts 17:31 names the fulfillment: God &lsquo;has fixed a day on which he will judge the world in righteousness by a man whom he has appointed&rsquo; — the throne and the judgment seat converge in Christ the king-judge.</p>",
    "8": "<p>Solomon&rsquo;s own residence &lsquo;built to the same design&rsquo; as the Hall of Judgment, set in a second courtyard. He also builds a matching palace for Pharaoh&rsquo;s daughter. The parallel construction for Solomon&rsquo;s Egyptian wife is the first architectural expression of what will become his undoing (1 Kgs 11:1-3): the women from foreign nations lead him into idolatry. The palace built for Pharaoh&rsquo;s daughter — the Egyptian connection — echoes the Egypt that Israel&rsquo;s kings were warned never to return to (Deut 17:16). The shadow of apostasy already falls across the palace complex.</p>",
    "9": "<p>All these structures built of costly hewn stones, &lsquo;trimmed to exact measurements, sawed smooth on every face.&rsquo; The precision of the stonework — sawed to measurement, smooth on every surface — reflects the artisanal care of those who build for divine use. Eph 2:20-22: the church is &lsquo;built on the foundation of the apostles and prophets, Christ Jesus himself being the cornerstone, in whom the whole structure, being joined together, grows into a holy temple in the Lord.&rsquo; The careful fitting of stones is the NT image for the community built by Christ.</p>",
    "10": "<p>Massive foundation stones — ten cubits and eight cubits. The foundation stones of the palace complex are the largest, costliest, most carefully placed elements of the entire structure — the visible part is less impressive than the invisible foundation. The theme of Christ as cornerstone: Eph 2:20, &lsquo;Christ Jesus himself being the cornerstone&rsquo;; 1 Pet 2:6, &lsquo;I am laying in Zion a stone, a cornerstone chosen and precious.&rsquo; The most important element of any building is what it rests on; the massive foundation of Solomon&rsquo;s palace is the architectural illustration of what the apostles apply to Christ.</p>",
    "11": "<p>Above the foundation: costly cut stones and cedar timber in alternating courses — the same construction method as the temple courts (6:36). The continuity of building technique across temple and palace: both are built by the same principles, the same materials. A shadow: the church and the kingdom share the same foundation, the same cornerstone, the same building material (living stones, 1 Pet 2:5). There is no sacred/secular split in God&rsquo;s architectural economy; all of human life that is built on Christ participates in the same sacred construction.</p>",
    "12": "<p>The great outer court enclosed by the same three-stone, one-cedar coursing as the inner court of the temple. The unity of material principle across temple and palace complex reinforces the point that the entire Solomonic construction project is a unified statement of Davidic-covenant fulfillment. The theme of the comprehensive kingdom: the Davidic king&rsquo;s reign encompasses both the sacred (temple) and the civil (palace complex) in a single redemptive project. The NT describes the same comprehensive scope: &lsquo;the kingdom of God&rsquo; encompasses not a sacred space alone but all of creation under Christ&rsquo;s lordship (Col 1:15-20).</p>",
    "13": "<p>Solomon sent to Tyre and brought Hiram. The Tyrian craftsman is brought to serve the building of YHWH&rsquo;s house. Tyre is a Gentile coastal city, a center of Phoenician maritime commerce — the nearest pagan cosmopolitan center to Israel. Solomon&rsquo;s solicitation of Tyrian expertise is the royal acknowledgment that the building of the house of God requires gifts that transcend Israel&rsquo;s own resources. A theme: the nations&rsquo; wealth and skills flowing into YHWH&rsquo;s house anticipates Isa 60:5-7 (the riches of the nations coming to Zion) and Rev 21:24-26 (the kings of the earth bringing their glory into the New Jerusalem).</p>",
    "14": "<p>Hiram: the son of a widow from Naphtali, his father a Tyrian bronze craftsman. He was &lsquo;filled with wisdom, understanding, and knowledge to do all kinds of work in bronze.&rsquo; The divine gifting for sacred construction: the same language used of Bezalel (Exod 35:31 — &lsquo;filled with the Spirit of God, with ability and intelligence, with knowledge and all craftsmanship&rsquo;) is applied to Hiram. Both are given divine wisdom for the sanctuary&rsquo;s material work. The Spirit of God equips craftsmen, not only prophets and priests. The NT extends this: the Spirit gives gifts to all believers for building the spiritual temple (1 Cor 12:7-11; Eph 4:7-12), not only to a sacred professional class.</p>",
    "15": "<p>Two bronze pillars, each eighteen cubits tall and twelve cubits in circumference. The scale is enormous — each pillar nearly nine meters tall. These monumental columns at the temple entrance are the first thing worshippers see as they approach YHWH&rsquo;s house. Their size communicates the weight and permanence of the divine presence within. The theme of the pillar as strength and establishment runs through the OT (YHWH as a pillar of cloud and fire, Exod 13:21-22) and into the NT: Rev 3:12, &lsquo;the one who conquers, I will make a pillar in the temple of my God.&rsquo;</p>",
    "16": "<p>Two bronze capitals, each five cubits high, set on top of the pillars. The capitals are the crowning elements, adding height and visual weight to the already massive pillars. The temple entrance is defined by crowned columns — the royal architectural statement that God&rsquo;s house is entered under the crowns of divine establishment. Phil 2:9-11: God &lsquo;has highly exalted him and bestowed on him the name that is above every name... to the glory of God the Father.&rsquo; Christ is the pillar crowned with glory above every power.</p>",
    "17": "<p>Latticework and chain garlands on the capitals — seven rows each. The number seven on the capitals: the fullness-number adorning the crowns of the pillars. The decorative work of the capitals communicates that divine power (the pillar) is adorned with completeness (seven). Heb 2:9: &lsquo;we see him who for a little while was made lower than the angels, namely Jesus, crowned with glory and honor because of the suffering of death.&rsquo; The crowned pillar is the NT&rsquo;s theological grammar for the exalted Son.</p>",
    "18": "<p>Two rows of pomegranates around each capital — one hundred pomegranates per row. Pomegranates are the fruit of the promised land (Num 13:23), the emblem of abundance and covenant blessing. Their presence on the temple pillars decorates the entrance to God&rsquo;s house with the symbols of covenant fulfillment: the land&rsquo;s abundance now adorning the dwelling of God. The theme of covenant faithfulness consummated: Gal 5:22-23 names the &lsquo;fruit of the Spirit&rsquo; as the NT equivalent — the divine abundance that marks those in whom God dwells.</p>",
    "19": "<p>The capitals designed as lily flowers, four cubits high. The lily motif on the pillars: lilies in the OT are associated with beauty and the beloved&rsquo;s garden (Song 2:1-2, &lsquo;I am a lily of the valleys&rsquo;; Song 6:3, &lsquo;he grazes among the lilies&rsquo;). The lily-topped pillars at the temple entrance transform the approach to God&rsquo;s house into the entrance to the garden of the beloved. The temple is the place of covenant intimacy. The Song of Solomon&rsquo;s imagery and the temple&rsquo;s lily capitals are both expressions of the same theological truth: YHWH&rsquo;s relationship with Israel is covenantal love, and the temple is the house of that love.</p>",
    "20": "<p>Pomegranates above the rounded section of each capital, beside the latticework — two hundred in total. The doubling of pomegranates reinforces the theme of covenant abundance: YHWH&rsquo;s house is surrounded by the signs of his blessing, visible before entry. The approaching worshipper sees fruit before they see the interior. The NT order is the same: the fruit of the Spirit is visible in the community before the inner mystery of union with Christ is fully disclosed. The outside communicates the inside.</p>",
    "21": "<p>A type: Jachin and Boaz — the names of the two pillars. &lsquo;He set up the right pillar and named it Jachin [יָכִין, &ldquo;he will establish&rdquo;], and he erected the left pillar and named it Boaz [בֹּעַז, &ldquo;in him is strength&rdquo;].&rsquo; Every worshipper entering YHWH&rsquo;s house passes between the twin declarations: &lsquo;He — YHWH — will establish&rsquo; and &lsquo;In him is strength.&rsquo; The pillar-names are a liturgical entry through divine proclamation. The NT applies this to Christ: Col 1:17, &lsquo;in him all things hold together&rsquo; (Boaz-strength); 2 Sam 7:12-13, &lsquo;I will establish his kingdom forever&rsquo; (Jachin-establishment). Rev 3:12: the victorious believer will &lsquo;never go out&rsquo; of the temple of God — made a permanent pillar of establishment and strength.</p>",
    "22": "<p>&lsquo;The tops of the pillars were crowned with lily-work. So the work of the pillars was complete.&rsquo; The completion of the pillars: crowned with lilies, adorned with chains, weighted with pomegranates, named with divine promise. They are the most theologically loaded architectural elements of the temple — the first and last impression of approaching YHWH&rsquo;s dwelling. The crown of lily-work at the top reaches upward; the foundation in the stone pavement reaches downward. Jesus&rsquo;s words to the church at Philadelphia: &lsquo;I will make him a pillar in the temple of my God... I will write on him the name of my God&rsquo; (Rev 3:12) — the believer incorporated into the pillar-identity, bearing the divine name as Jachin and Boaz bore YHWH&rsquo;s promise.</p>",
    "23": "<p>A shadow: the molten sea — a circular cast-metal basin ten cubits across, five cubits high, thirty cubits in circumference — for the priestly purifications. The &lsquo;sea&rsquo; designation is cosmologically significant: in ANE cosmology, the sea represents primordial chaos (the waters of Gen 1:2) that creation orders and bounds. The bronze sea within the temple complex represents the cosmic waters brought under control, bounded, consecrated for purification. Rev 4:6: &lsquo;before the throne there was as it were a sea of glass, like crystal.&rsquo; The molten sea in motion (liquid bronze) is transformed in the heavenly vision into a crystallized stillness — chaos eternally stilled, the waters of judgment become the waters of transparent holiness before the throne.</p>",
    "24": "<p>Gourd-shaped ornaments encircling the sea — ten per cubit, cast in two rows. The vegetative ornaments on the sea (gourds = food, abundance) adorn the purification basin. The sea of washing is surrounded by the motifs of sustenance and life. The baptismal echo in the NT: water that purifies and the bread of life belong together — John 6 (bread of life discourse) follows John 5 (healing at the pool) and precedes John 7 (streams of living water). The sea of purification surrounded by gourd-abundance anticipates the eucharistic abundance that surrounds baptismal identity.</p>",
    "25": "<p>A shadow: the sea rests on twelve bronze oxen — three facing each cardinal direction. The twelve oxen correspond to the twelve tribes of Israel: the entire covenant people bear the sea of divine purification. The corporate nature of purification: no Israelite approaches God on purely individual terms; the covenant community as a whole bears the waters. 1 Cor 12:13: &lsquo;we were all baptized into one body — Jews or Greeks, slaves or free — and all were made to drink of one Spirit.&rsquo; The twelve oxen carrying the sea figures the one body in whom all drink the one Spirit.</p>",
    "26": "<p>The sea is a handbreadth thick, holds two thousand baths. The handbreadth thickness of the metal: a human dimension (the width of a hand) contains the water that purifies a nation. The measure of divine grace always exceeds the container: two thousand baths of water, held in a vessel measurable by a human hand. Eph 3:20: &lsquo;to him who is able to do far more abundantly than all that we ask or think.&rsquo; The priestly sea holds far more than one person needs; the Spirit&rsquo;s purification is inexhaustible.</p>",
    "27": "<p>Ten bronze stands, each four cubits square and three cubits high, for the portable basins. The stands are mobile — they can be moved to where the washing is needed. The theme of accessible purification: ten stands, one for each of the ten court positions, bringing the basin where the priest serves. The mobility of grace: the NT&rsquo;s Spirit is not stationary (not fixed to the temple or Jerusalem) but goes where God sends, purifying where Christ has been named (Acts 2:38-39: &lsquo;the promise is for you and for your children and for all who are far off&rsquo;).</p>",
    "28": "<p>The stands constructed with panels set within frames. The architectural detail of structured panels — supported and bounded by frames — is the building-block of the stands&rsquo; stability. The panel within the frame is the elementary unit of order. A theme: the revelation of God is structured (given in the bounded, framed form of Scripture, covenant, and canon), not amorphous. 2 Tim 3:16: &lsquo;all Scripture is breathed out by God.&rsquo; The frame of the canon contains the panels of divine revelation.</p>",
    "29": "<p>Panels carved with lions, oxen, and cherubim — the creatures of Ezekiel&rsquo;s throne vision (Ezek 1:10 names exactly these creatures: lion, ox, man, eagle). The stands are not merely functional but theologically decorated: the washing basins they carry are attended by the same throne-creatures who attend YHWH&rsquo;s heavenly chariot. Rev 4:7 lists them again: lion, ox, man with face, eagle. The priestly purification of Israel is performed in the shadow of the heavenly throne — the same creatures who attend God&rsquo;s heavenly sovereignty attend the earthly act of cleansing.</p>",
    "30": "<p>Each stand has four bronze wheels with axles, and four corner supports. The wheeled stands are mobile, like the throne-chariot of Ezekiel 1 with its four wheels. The stands are not static platforms but mobile carriers of purification — the washing follows the worshipper where service is required. The Spirit as the mobile agent of cleansing and empowerment (John 3:8: &lsquo;the wind blows where it wishes... so it is with everyone born of the Spirit&rsquo;) is the NT fulfillment of the wheeled stand: purification that moves.</p>",
    "31": "<p>The stand&rsquo;s circular collar and opening, one cubit above the top, with garlands. The architectural ornament of the opening: the place where the basin rests on the stand is ringed with garlands — the place of purification is decorated with beauty. The theme that the means of grace are adorned, not bare: the OT tabernacle and temple are covered in beauty, not functional plainness. Beauty in the place of worship is a theological statement about the character of the God worshipped. The NT&rsquo;s &lsquo;whatever is beautiful, whatever is admirable&rsquo; (Phil 4:8) reflects the same theological instinct.</p>",
    "32": "<p>Four wheels, each a cubit and a half in diameter, below the panels. The wheels of the stands: practical for mobility, but their diameter and proportion follow the same careful measurements as every element of the temple complex. Precision in the service of worship. 1 Cor 14:40: &lsquo;all things should be done decently and in order&rsquo; — the NT principle of ordered worship is built into the architectural precision of every wheel, every cubit, every measurement of the temple service.</p>",
    "33": "<p>The wheels made like chariot wheels — axles, hubs, spokes, and rims all of cast bronze. The stands carry purification on chariot-wheels — the vehicle of royal military power repurposed as the carrier of priestly grace. The king&rsquo;s chariot fights and conquers; the priest&rsquo;s wheeled stand washes and cleanses. The NT redefinition of power: the cross is the royal chariot of the suffering servant, the vehicle of the decisive victory that is also the act of cleansing (Rev 1:5-6: &lsquo;freed us from our sins by his blood and made us a kingdom, priests&rsquo;).</p>",
    "34": "<p>Four corner supports cast as one piece with the stand itself. Structural integrity: the supports are not attached but integral — cast as one with the body of the stand. The inseparability of support and structure is the building principle. A theme of Christ: he does not support the church from the outside (an external helper) but is the body into which the church is built — &lsquo;the whole body, joined and held together by every joint with which it is equipped&rsquo; (Eph 4:16). The support is not added; it is constitutive.</p>",
    "35": "<p>A round band at the top, with projections and panels cast as one piece. The integration of every element into a single casting: the band, the projections, the panels are not assembled but cast together. The unity of material in the bronze stands images the organic unity of the community built in Christ. 1 Cor 12:12: &lsquo;just as the body is one and has many members... so it is with Christ.&rsquo; The organic unity of one casting, many shapes.</p>",
    "36": "<p>Cherubim, lions, and palm trees engraved on the panels and borders. The same three elements as the temple interior (6:29): cherubim (divine guardianship), lions (royal power), palm trees (covenant life and righteousness). The throne-creatures of Ezekiel 1 on the temple's mobile basins: the entire worship apparatus of Israel is stamped with the imagery of divine sovereignty. Every element of the service of God points to the one who is YHWH's enthroned king, attended by cherubim and lion — the Lamb who is the Lion (Rev 5:5-6).</p>",
    "37": "<p>&lsquo;He made all ten stands by this same design — identical cast, identical measurements, identical form.&rsquo; The ten stands are uniform — one pattern for all. The theme of divine consistency: the grace given through every stand is the same grace. 1 Cor 12:11: &lsquo;all these are empowered by one and the same Spirit, who apportions to each one individually as he wills.&rsquo; The same Spirit behind every gift, as the same design behind every stand. Uniformity of source; variety of placement.</p>",
    "38": "<p>Ten bronze basins, each holding forty baths and four cubits across — one per stand. The forty-bath capacity of each basin: forty again, the number of testing and provision (forty years, forty days). The basin that washes the priest holds the water of forty — purification in the fullness of the testing-and-provision number. The NT baptism carries the same weight: passing through the waters of death into life (Rom 6:3-4), as Israel passed through the Red Sea (the &lsquo;baptism&rsquo; of 1 Cor 10:2), as the forty wilderness years were the baptism-in-testing of the covenant people.</p>",
    "39": "<p>Five stands on the south, five on the north; the sea on the south-east corner. The bilateral symmetry of the ten stands (five and five) reflects the balanced provision of purification for all who approach from any direction. The sea set at the southeast: the place of sunrise and the direction of Egypt (south and east of Jerusalem). The largest purification vessel points toward where the people came from — toward the Exodus, the original passage through water. The temple&rsquo;s spatial arrangement remembers Israel&rsquo;s story.</p>",
    "40": "<p>Hiram completed all the work he did for King Solomon on the house of the LORD. The Gentile craftsman&rsquo;s completion of his commission is the culmination of the Tyrian-Israelite collaboration. A theme: the building of the house of God involves the gifts of those beyond Israel — the Gentile&rsquo;s skill serves YHWH&rsquo;s house. Eph 2:19-22 articulates the NT fullness: &lsquo;you are no longer strangers and aliens, but you are fellow citizens with the saints and members of the household of God.&rsquo; Hiram the Tyrian craftsman is a preview of the Gentile co-workers of God&rsquo;s building project.</p>",
    "41": "<p>An inventory of the completed items. The list begins with the two pillars, the capitals, the latticework — the most visible elements of the temple entrance. The inventory is the official record of completion. A shadow: Rev 5:8-14 contains the heavenly inventory of the worship of the completed temple — the twenty-four elders, the four living creatures, the prayers of the saints in golden bowls. What Solomon inventories in bronze and gold, John sees in glory and intercession.</p>",
    "42": "<p>Four hundred pomegranates for the two pieces of latticework — two rows of one hundred each, per piece. The pomegranate count is enormous: the temple entrance is overwhelmed with the symbol of covenant abundance. The scale of covenant blessing displayed at the threshold communicates that entering YHWH&rsquo;s presence means entering a superabundance of life. John 10:10: &lsquo;I came that they may have life and have it abundantly.&rsquo; The four hundred pomegranates at the entrance are the architectural statement that Jesus makes verbally.</p>",
    "43": "<p>The ten stands and ten basins. The completeness of the purification apparatus: ten stands, ten basins, symmetrically arranged. All ten carry the same water; all ten serve the same purpose. The theme of the adequacy of the provision: God&rsquo;s purification is sufficient for every servant who approaches. Heb 10:14: &lsquo;by a single offering he has perfected for all time those who are being sanctified.&rsquo; The ten stands are adequate for the temple service; the one offering is adequate for all time.</p>",
    "44": "<p>The one sea and the twelve oxen beneath it. In this inventory, the sea and its twelve oxen are a single unit: the purification and its covenant foundation are inseparable. The twelve oxen do not merely support the sea; they present it. The covenant community (twelve tribes) presents the means of purification to the worshipper. The NT community (the church) is the body through which the waters of baptism and the word of cleansing are presented to the world. The twelve oxen beneath the sea figure the apostolic community bearing the gospel&rsquo;s cleansing.</p>",
    "45": "<p>The pots, shovels, and basins — the practical implements of temple service. The most mundane elements of the temple inventory are included: the equipment for removing ashes, for carrying coals, for managing the altar. The theme of sanctified ordinariness: the pots and shovels of the temple are as holy as the cherubim, because they serve in the house of God. The NT makes the same claim: &lsquo;whether you eat or drink, or whatever you do, do all to the glory of God&rsquo; (1 Cor 10:31). The mundane becomes sacred in the service of God.</p>",
    "46": "<p>The bronze cast in the clay soil of the Jordan plain between Succoth and Zarethan. The Jordan plain as the casting site: the Jordan is the boundary-water of the covenant land, the crossing-place of entry into the promise. The sacred bronze vessels for the temple are formed at the Jordan — at the site of Israel&rsquo;s original crossing into the land. The baptismal geography of the Jordan: Jesus is baptized in the Jordan (Matt 3:13-17); the place of covenant-entry is sanctified by the Son&rsquo;s own passage through it.</p>",
    "47": "<p>&lsquo;Solomon left all the vessels unweighed because there were so many; the total weight of the bronze was never determined.&rsquo; The bronze of the temple furnishings was too abundant to weigh — a deliberate statement of immeasurable provision. The theme of divine inexhaustibility: YHWH&rsquo;s provision for worship cannot be quantified. Eph 3:8: &lsquo;the unsearchable riches of Christ&rsquo; — the apostolic ministry is to make known what cannot be fully measured. The temple&rsquo;s unweighed bronze is the material figure of the inexhaustible wealth of Christ.</p>",
    "48": "<p>Solomon also made all the furnishings for the LORD&rsquo;s house — the gold altar and the gold table for the bread of the Presence. The gold altar (for incense) and the table for the bread of the Presence are the two pieces of furniture in the holy place, accessible to priests daily. The bread of the Presence (twelve loaves, renewed weekly) represents the twelve tribes constantly before YHWH. Heb 9:2 lists it in the holy place. John 6:35: &lsquo;I am the bread of life&rsquo; — the twelve loaves of the Presence were always pointing toward the one loaf who feeds the whole covenant people, presented permanently before the Father.</p>",
    "49": "<p>Ten golden lampstands — five right, five left, before the inner sanctuary — with flowers, lamps, and tongs of gold. The ten lampstands multiply the tabernacle&rsquo;s seven-branched menorah (Exod 25:31-40): ten lampstands extending light in both directions before the inner sanctuary. John 8:12: &lsquo;I am the light of the world.&rsquo; Rev 1:12-13: John sees seven golden lampstands, with the Son of Man walking among them — the lampstands are the churches, and Christ is the light of their lampstands. The ten Solomon places become the seven John sees, with Christ as their source and sustainer.</p>",
    "50": "<p>The cups, snuffers, basins, dishes, and fire pans of pure gold; gold hinges for the doors of both the Most Holy Place and the main hall. Gold hinges: even the functional connectors between the sacred spaces are pure gold — there is no cheap material at the threshold of the holy. The theme of total consecration: in the holy place, nothing is left at ordinary material value; everything is raised to the highest. 1 Cor 3:12-15: the work built on Christ&rsquo;s foundation will be tested by fire; gold and silver survive. The temple&rsquo;s gold hinges are the architectural form of the apostolic principle: build with gold, not wood.</p>",
    "51": "<p>A direct fulfillment trajectory: &lsquo;All the work King Solomon did on the house of the LORD was now complete.&rsquo; The completion of the temple is the OT&rsquo;s highest moment of the dwelling of God with Israel — and it is immediately followed by the ark entering and the glory filling the house (1 Kgs 8:10-11). Each completion leads to a filling. John 19:30: &lsquo;It is finished&rsquo; — the completion of Christ&rsquo;s atoning work is followed by the Spirit&rsquo;s filling (John 20:22; Acts 2:4). Solomon brings in David&rsquo;s dedicated treasures at the completion; Christ brings in his Father&rsquo;s entire covenant economy — the law, prophets, psalms — completed and presented in him (Luke 24:44). The temple&rsquo;s completion is the OT form of the passion&rsquo;s completion.</p>"
  }
}

def main():
    existing = load_comm('mkt-christ', '1kings')
    merge_comm(existing, KINGS1)
    save_comm('mkt-christ', '1kings', existing)
    count = sum(len(v) for v in KINGS1.values())
    print(f'1kings mkt-christ ch 6-7: wrote {count} verses')

if __name__ == '__main__':
    main()
